import React, { useState, useEffect } from 'react';
import { ToolType, AppState, GenerationResult } from './types';
import { Icons, STYLES } from './constants';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    activeTool: ToolType.PROMPT_GEN,
    isProcessing: false,
    result: null,
    error: null
  });

  const [files, setFiles] = useState<File[]>([]);
  const [prompt, setPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState(STYLES[0].name);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 1024);
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleToolChange = (tool: ToolType) => {
    setState(prev => ({ ...prev, activeTool: tool, result: null, error: null }));
    setFiles([]);
    setPrompt('');
  };

  const processAction = async () => {
    if (state.isProcessing) return;
    setState(prev => ({ ...prev, isProcessing: true, error: null, result: null }));
    try {
      let result: GenerationResult = {};

      switch (state.activeTool) {
        case ToolType.ENHANCE:
          if (!files[0]) throw new Error("Sube una imagen.");
          const url = await GeminiService.enhanceImage(files[0]);
          result = { url, type: 'image', technicalBreakdown: "Reconstrucción sub-pixel completada mediante red neuronal de Gemini 3 Pro." };
          break;
        case ToolType.PROMPT_GEN:
          if (!files[0]) throw new Error("Sube una imagen.");
          const analysis = await GeminiService.analyzeImage(files[0]);
          result = { content: analysis.prompt, technicalBreakdown: analysis.tech, type: 'text' };
          break;
        case ToolType.TECHNICAL:
          if (!files[0]) throw new Error("Sube una imagen.");
          const techRes = await GeminiService.technicalOptimization(files[0], prompt || "Optimización estándar");
          result = { url: techRes.imageUrl, content: techRes.log, type: 'image' };
          break;
        case ToolType.STYLE:
          if (!files[0]) throw new Error("Sube una imagen.");
          const styleUrl = await GeminiService.applyExpertStyle(files[0], selectedStyle);
          result = { url: styleUrl, type: 'image', technicalBreakdown: `Aplicando parámetros de ${selectedStyle} basados en base de datos artística.` };
          break;
        case ToolType.STICKER:
          if (!prompt) throw new Error("Define tu sticker.");
          const stickerUrl = await GeminiService.createAdvancedSticker(prompt);
          result = { url: stickerUrl, type: 'video' };
          break;
      }

      setState(prev => ({ ...prev, isProcessing: false, result }));
    } catch (err: any) {
      setState(prev => ({ ...prev, isProcessing: false, error: err.message }));
    }
  };

  const navItems = [
    { id: ToolType.PROMPT_GEN, label: "Arquitecto", icon: <Icons.Analyze /> },
    { id: ToolType.ENHANCE, label: "Upscaling", icon: <Icons.Enhance /> },
    { id: ToolType.STYLE, label: "Arte RAG", icon: <Icons.Style /> },
    { id: ToolType.TECHNICAL, label: "Laboratorio", icon: <Icons.Technical /> },
    { id: ToolType.STICKER, label: "Veo Studio", icon: <Icons.Sticker /> }
  ];

  return (
    <div className="flex flex-col lg:flex-row h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans">
      {/* Sidebar */}
      {!isMobile && (
        <aside className="w-80 border-r border-white/10 bg-black/40 p-8 flex flex-col gap-8">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-500 rounded-lg shadow-lg shadow-indigo-500/20">
              <Icons.Technical />
            </div>
            <h1 className="text-xl font-black tracking-tighter uppercase">Nano<span className="text-indigo-400">Vivid</span></h1>
          </div>

          <nav className="space-y-2">
            {navItems.map(item => (
              <button
                key={item.id}
                onClick={() => handleToolChange(item.id)}
                className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${state.activeTool === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-white/5'}`}
              >
                {item.icon}
                <span className="text-xs font-bold uppercase tracking-widest">{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="mt-auto p-4 bg-white/5 rounded-2xl border border-white/5">
            <p className="text-[10px] text-slate-500 font-bold uppercase mb-2">Estado del Sistema</p>
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <span className="text-[10px] font-mono">GEMINI_3_EXP_MODE_ACTIVE</span>
            </div>
          </div>
        </aside>
      )}

      {/* Main content */}
      <main className="flex-1 flex flex-col h-full relative p-6 lg:p-12 overflow-y-auto no-scrollbar">
        <header className="flex flex-col md:flex-row justify-between items-start mb-12 gap-6">
          <div>
            <span className="text-indigo-400 text-[10px] font-black uppercase tracking-[0.3em]">IA Vision Laboratory</span>
            <h2 className="text-4xl font-black tracking-tighter text-white">
              {state.activeTool === ToolType.PROMPT_GEN && "Arquitecto de Prompts"}
              {state.activeTool === ToolType.ENHANCE && "Upscaling Neural 4K"}
              {state.activeTool === ToolType.TECHNICAL && "Laboratorio de Código"}
              {state.activeTool === ToolType.STYLE && "Transferencia de Arte RAG"}
              {state.activeTool === ToolType.STICKER && "Generador Veo 3.1"}
            </h2>
          </div>
          <button 
            onClick={processAction}
            disabled={state.isProcessing}
            className="px-10 py-4 bg-white text-black rounded-full font-black text-xs uppercase tracking-widest hover:scale-105 active:scale-95 transition-all disabled:opacity-20 shadow-2xl"
          >
            {state.isProcessing ? "Procesando..." : "Ejecutar Motor IA"}
          </button>
        </header>

        {state.error && <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-xl text-[10px] font-bold">⚠️ {state.error}</div>}

        <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 flex-1">
          <div className="xl:col-span-4 space-y-8">
            <section className="bg-white/5 p-6 rounded-3xl border border-white/10 space-y-6">
              <h3 className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Entrada de Datos</h3>

              {state.activeTool !== ToolType.STICKER && (
                <div className="aspect-square bg-black/40 rounded-2xl border-2 border-dashed border-white/10 flex items-center justify-center relative overflow-hidden group cursor-pointer" onClick={() => document.getElementById('file-input')?.click()}>
                  <input type="file" id="file-input" className="hidden" onChange={(e) => setFiles(Array.from(e.target.files || []))} />
                  {files[0] ? (
                    <img src={URL.createObjectURL(files[0])} className="w-full h-full object-cover group-hover:scale-110 transition-transform" />
                  ) : (
                    <div className="text-center">
                      <div className="text-4xl text-slate-700 mb-2">+</div>
                      <p className="text-[9px] font-bold text-slate-500 uppercase">Cargar Imagen</p>
                    </div>
                  )}
                </div>
              )}

              {(state.activeTool === ToolType.STICKER || state.activeTool === ToolType.TECHNICAL) && (
                <textarea 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Instrucciones técnicas o prompt..."
                  className="w-full h-32 bg-black/40 rounded-xl border border-white/10 p-4 text-xs font-mono focus:ring-2 focus:ring-indigo-500 outline-none"
                />
              )}

              {state.activeTool === ToolType.STYLE && (
                <div className="grid grid-cols-1 gap-2">
                  {STYLES.map(s => (
                    <button 
                      key={s.id} 
                      onClick={() => setSelectedStyle(s.name)}
                      className={`p-4 rounded-xl border text-left flex items-center gap-3 transition-all ${selectedStyle === s.name ? 'border-indigo-500 bg-indigo-500/10' : 'border-white/5'}`}
                    >
                      <div className={`w-3 h-3 rounded-full ${s.previewColor}`} />
                      <span className="text-[10px] font-bold uppercase">{s.name}</span>
                    </button>
                  ))}
                </div>
              )}
            </section>
          </div>

          <div className="xl:col-span-8 space-y-8">
            <section className="bg-black/40 border border-white/10 rounded-[2.5rem] p-4 lg:p-8 min-h-[500px] flex flex-col relative group">
              {state.isProcessing && (
                <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-xl flex flex-col items-center justify-center">
                  <div className="w-64 h-1 bg-white/10 rounded-full overflow-hidden mb-4">
                    <div className="h-full bg-indigo-500 animate-[loading_2s_infinite]" />
                  </div>
                  <p className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-400">Analizando Redes Neuronales</p>
                </div>
              )}

              <div className="flex-1 rounded-2xl bg-black/20 overflow-hidden flex items-center justify-center relative">
                {state.result ? (
                  state.result.type === 'text' ? (
                    <div className="p-8 w-full max-w-2xl space-y-6">
                      <div className="p-6 bg-indigo-500/5 border border-indigo-500/10 rounded-2xl">
                        <label className="text-[9px] font-black text-indigo-400 block mb-2 uppercase">Prompt Maestro Generado</label>
                        <p className="text-sm font-medium leading-relaxed italic">"{state.result.content}"</p>
                      </div>
                    </div>
                  ) : state.result.type === 'video' ? (
                    <video src={state.result.url} autoPlay loop muted className="max-w-full max-h-[60vh] rounded-xl shadow-2xl" />
                  ) : (
                    <img src={state.result.url} className="max-w-full max-h-[60vh] rounded-xl shadow-2xl transition-all hover:scale-[1.02]" />
                  )
                ) : (
                  <div className="opacity-10 text-center">
                    <Icons.Technical />
                    <p className="text-[10px] font-black uppercase tracking-[0.2em] mt-4">Canvas de Salida</p>
                  </div>
                )}
              </div>

              {state.result?.technicalBreakdown && (
                <div className="mt-8 pt-8 border-t border-white/5">
                  <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Log de Análisis Técnico</h4>
                  <div className="font-mono text-[11px] text-slate-400 leading-relaxed bg-black/40 p-4 rounded-xl border border-white/5">
                    {state.result.technicalBreakdown}
                  </div>
                </div>
              )}
            </section>
          </div>
        </div>
      </main>

      {/* Mobile nav */}
      {isMobile && (
        <nav className="fixed bottom-0 left-0 right-0 h-20 bg-black/90 backdrop-blur-xl border-t border-white/10 flex items-center justify-around px-2 z-[100] pb-safe">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => handleToolChange(item.id)}
              className={`flex flex-col items-center gap-1 flex-1 ${state.activeTool === item.id ? 'text-indigo-400' : 'text-slate-500'}`}
            >
              {item.icon}
              <span className="text-[8px] font-black uppercase tracking-tighter">{item.label}</span>
            </button>
          ))}
        </nav>
      )}

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default App;

{
  "name": "NanoVivid Studio Pro",
  "description": "Plataforma de ingeniería visual con Gemini 3 Pro. Incluye análisis técnico de fotografía, optimización mediante ejecución de código y transferencia de estilo experta.",
  "requestFramePermissions": [
    "camera"
  ]
}

