import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private static async getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async fileToBase64(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
    });
  }

  static async remixImages(file1: File, file2: File, prompt: string): Promise<string> {
    const ai = await this.getAI();
    const [b1, b2] = await Promise.all([this.fileToBase64(file1), this.fileToBase64(file2)]);

    const finalPrompt = prompt || "Fusion these two images into a new unique concept. Use the structure and composition of the first image and the style, textures, and subject details of the second image. Create a high-quality, professional result.";

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: b1, mimeType: file1.type } },
          { inlineData: { data: b2, mimeType: file2.type } },
          { text: finalPrompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("Fallo en la fusión de conceptos.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  static async analyzeContent(file: File): Promise<any> {
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: "Act as a Prompt Engineer for image and video generation models. Analyze this content and provide a Master Prompt for recreation and a Motion Prompt for animation." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recreationPrompt: { type: Type.STRING, description: "Detailed prompt for Midjourney/Stable Diffusion" },
            animationPrompt: { type: Type.STRING, description: "Technical motion prompt for Runway/Luma/Pika" }
          },
          required: ["recreationPrompt", "animationPrompt"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  }

  static async editWithStyle(file: File, instruction: string, style?: string): Promise<string> {
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);
    const fullPrompt = style ? `Transform this image using the ${style} aesthetic. Task: ${instruction || 'Apply style accurately.'}` : instruction;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: fullPrompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("Error en el procesado de imagen.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }
}

import React, { useState } from 'react';
import { ToolType, AppState, GenerationResult } from './types';
import { Icons, STYLES } from './constants';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    activeTool: ToolType.REMIX,
    isProcessing: false,
    result: null,
    error: null
  });

  const [files, setFiles] = useState<File[]>([]);
  const [prompt, setPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState(STYLES[0].name);

  const handleToolChange = (tool: ToolType) => {
    setState(prev => ({ ...prev, activeTool: tool, result: null, error: null }));
    setFiles([]);
    setPrompt('');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, index: number = 0) => {
    const newFile = e.target.files?.[0];
    if (newFile) {
      const newFiles = [...files];
      newFiles[index] = newFile;
      setFiles(newFiles);
    }
  };

  const processAction = async () => {
    if (state.isProcessing) return;
    setState(prev => ({ ...prev, isProcessing: true, error: null, result: null }));

    try {
      let result: GenerationResult;

      switch (state.activeTool) {
        case ToolType.REMIX:
          if (files.length < 2) throw new Error("Sube dos imágenes para el Remix.");
          const remixUrl = await GeminiService.remixImages(files[0], files[1], prompt);
          result = { url: remixUrl, type: 'image' };
          break;
        case ToolType.ANALYZE:
          if (!files[0]) throw new Error("Sube una imagen para analizar.");
          const analysis = await GeminiService.analyzeContent(files[0]);
          result = { analysis, type: 'analysis' };
          break;
        case ToolType.STYLE:
          if (!files[0]) throw new Error("Sube una imagen primero.");
          const styleUrl = await GeminiService.editWithStyle(files[0], prompt, selectedStyle);
          result = { url: styleUrl, type: 'image' };
          break;
        case ToolType.EDIT:
          if (!files[0]) throw new Error("Sube una imagen primero.");
          const editUrl = await GeminiService.editWithStyle(files[0], prompt);
          result = { url: editUrl, type: 'image' };
          break;
        default:
          throw new Error("Opción no válida.");
      }

      setState(prev => ({ ...prev, isProcessing: false, result }));
    } catch (err: any) {
      setState(prev => ({ ...prev, isProcessing: false, error: err.message }));
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado al portapapeles");
  };

  return (
    <div className="flex h-screen bg-[#020617] text-slate-200 overflow-hidden">
      {/* Sidebar Lateral */}
      <aside className="w-80 border-r border-white/5 bg-black/40 flex flex-col pt-safe">
