import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private static async getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async ensureProKey() {
    // @ts-ignore
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        // @ts-ignore
        await window.aistudio.openSelectKey();
      }
    }
  }

  static async fileToBase64(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
    });
  }

  static async remixImages(file1: File, file2: File, prompt: string): Promise<string> {
    await this.ensureProKey();
    const ai = await this.getAI();
    const [b1, b2] = await Promise.all([this.fileToBase64(file1), this.fileToBase64(file2)]);

    const finalPrompt = prompt 
      ? `High-quality concept fusion: Combine the layout/composition of image 1 with the subjects, textures, and aesthetic details of image 2. Context: ${prompt}. Professional lighting, 4k resolution, sharp details.`
      : "Masterpiece concept fusion. Use the spatial structure and composition of the first image. Extract the core subjects, materials, and artistic style from the second image and merge them into a new, highly detailed 4k photograph. Realistic textures, cinematic lighting.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          { inlineData: { data: b1, mimeType: file1.type } },
          { inlineData: { data: b2, mimeType: file2.type } },
          { text: finalPrompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("Fallo en la generación de alta calidad para Remix.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  static async analyzeContent(file: File): Promise<any> {
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: "Act as a Master Prompt Engineer. Analyze this visual content. Provide: 1. A 'Master Prompt' for recreating this exact scene in high-end AI generators (mention lighting, lens, textures). 2. A 'Motion Prompt' specifically designed for video diffusion models like Runway or Luma to animate the scene naturally." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recreationPrompt: { type: Type.STRING, description: "Detailed reconstruction prompt" },
            animationPrompt: { type: Type.STRING, description: "Technical motion/camera prompt" }
          },
          required: ["recreationPrompt", "animationPrompt"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  }

  static async editWithStyle(file: File, instruction: string, style?: string): Promise<string> {
    await this.ensureProKey();
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);

    // Prompt agresivo para forzar la transformación de estilos (ej: de anime a real)
    const stylePrompt = style 
      ? `TOTAL TRANSFORMATION: Interpret this stylized/artistic image as a high-end, hyper-realistic Live Action photograph. 
         Style: ${style}. 
         Instructions: Convert all non-realistic features (anime eyes, sketch lines, cartoon proportions) into realistic human/object features. 
         Use cinematic Arri Alexa lighting, natural skin textures, 8k resolution. ${instruction}`
      : instruction;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: stylePrompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("La IA no pudo procesar la transformación de estilo.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }
}

import React, { useState } from 'react';
import { ToolType, AppState, GenerationResult } from './types';
import { Icons, STYLES } from './constants';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    activeTool: ToolType.REMIX,
    isProcessing: false,
    result: null,
    error: null
  });

  const [files, setFiles] = useState<File[]>([]);
  const [prompt, setPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState(STYLES[0].name);

  const handleToolChange = (tool: ToolType) => {
    setState(prev => ({ ...prev, activeTool: tool, result: null, error: null }));
    setFiles([]);
    setPrompt('');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, index: number = 0) => {
    const newFile = e.target.files?.[0];
    if (newFile) {
      const newFiles = [...files];
      newFiles[index] = newFile;
      setFiles(newFiles);
    }
  };

  const handleRandomIdea = () => {
    const ideas = [
      "Fusión orgánica: combina la arquitectura con el follaje selvático",
      "Unión cibernética: integra circuitos neón en el sujeto",
      "Estilo acuarela cósmica: usa la textura de galaxias",
      "Estatua de mármol viviente: transforma al sujeto en piedra pulida con grietas de oro",
      "Realismo sucio cinematográfico: añade lluvia, barro y luces de ciudad nocturna"
    ];
    setPrompt(ideas[Math.floor(Math.random() * ideas.length)]);
  };

  const processAction = async () => {
    if (state.isProcessing) return;
    setState(prev => ({ ...prev, isProcessing: true, error: null, result: null }));

    try {
      let result: GenerationResult;

      switch (state.activeTool) {
        case ToolType.REMIX:
          if (!files[0] || !files[1]) throw new Error("Necesitas subir dos imágenes (Base y Concepto) para el Remix.");
          const remixUrl = await GeminiService.remixImages(files[0], files[1], prompt);
          result = { url: remixUrl, type: 'image' };
          break;
        case ToolType.ANALYZE:
          if (!files[0]) throw new Error("Sube la imagen que deseas analizar.");
          const analysis = await GeminiService.analyzeContent(files[0]);
          result = { analysis, type: 'analysis' };
          break;
        case ToolType.STYLE:
          if (!files[0]) throw new Error("Sube la imagen para la transformación Live Action.");
          const styleUrl = await GeminiService.editWithStyle(files[0], prompt, selectedStyle);
          result = { url: styleUrl, type: 'image' };
          break;
        case ToolType.EDIT:
          if (!files[0]) throw new Error("Sube una imagen para editar.");
          const editUrl = await GeminiService.editWithStyle(files[0], prompt);
          result = { url: editUrl, type: 'image' };
          break;
        default:
          throw new Error("Opción no válida.");
      }

      setState(prev => ({ ...prev, isProcessing: false, result }));
    } catch (err: any) {
      setState(prev => ({ ...prev, isProcessing: false, error: err.message }));
    }
  };

