          <div className="flex items-center gap-3 mb-8 group cursor-default">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-xl shadow-indigo-600/30 group-hover:scale-110 transition-transform">
              <Icons.Remix />
            </div>
            <h1 className="font-black text-xl tracking-tighter">NANO<span className="text-indigo-400">STUDIO</span></h1>
          </div>

          <nav className="space-y-1">
            {[
              { id: ToolType.REMIX, label: "Remix Concept", icon: <Icons.Remix /> },
              { id: ToolType.ANALYZE, label: "Analizador Pro", icon: <Icons.Analyze /> },
              { id: ToolType.STYLE, label: "Live Action", icon: <Icons.Style /> },
              { id: ToolType.EDIT, label: "Editor Libre", icon: <Icons.Edit /> }
            ].map(item => (
              <button
                key={item.id}
                onClick={() => handleToolChange(item.id)}
                className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${state.activeTool === item.id ? 'bg-indigo-500/10 text-white border border-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.1)]' : 'text-slate-500 hover:text-slate-300'}`}
              >
                {item.icon}
                <span className="text-xs font-bold uppercase tracking-widest">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar">
          <div className="space-y-4">
            <h3 className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em]">Configuración</h3>

