                  {files[idx] ? (
                    <img src={URL.createObjectURL(files[idx])} className="w-full h-full object-cover" alt="Preview" />
                  ) : (
                    <div className="text-center p-4">
                      <p className="text-[10px] font-bold text-slate-400 uppercase">{idx === 0 ? "Imagen Base" : "Concepto/Estilo"}</p>
                      <p className="text-[9px] text-slate-600 mt-1 uppercase">Sube un archivo</p>
