import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private static async getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async fileToBase64(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
    });
  }

  static async remixImages(file1: File, file2: File, prompt: string): Promise<string> {
    const ai = await this.getAI();
    const [b1, b2] = await Promise.all([this.fileToBase64(file1), this.fileToBase64(file2)]);

    // Prompt optimizado para gemini-2.5-flash-image
    const finalPrompt = `CONCEPT REMIX: Create a new high-resolution image. 
    Take the layout and basic geometry from IMAGE 1. 
    Infuse it with the textures, subjects, colors, and artistic style of IMAGE 2. 
    Instruction: ${prompt || 'Merge them into a cohesive masterpiece.'}. 
    Output should be a clean, sharp, professional result.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: b1, mimeType: file1.type } },
          { inlineData: { data: b2, mimeType: file2.type } },
          { text: finalPrompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("Error en la fusión Flash-Image.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  static async analyzeContent(file: File): Promise<any> {
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: "Analyze this image and provide: 1. A master recreation prompt for stable diffusion. 2. A motion prompt for video animation. Response MUST be in JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recreationPrompt: { type: Type.STRING },
            animationPrompt: { type: Type.STRING }
          },
          required: ["recreationPrompt", "animationPrompt"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  }

  static async editWithStyle(file: File, instruction: string, style?: string): Promise<string> {
    const ai = await this.getAI();
    const b64 = await this.fileToBase64(file);

    // Prompt agresivo para asegurar que el estilo CAMBIE de verdad
    const stylePrompt = `STYLE TRANSFORMATION: Completely redraw this image in the style of: ${style || 'Custom Style'}.
    KEEP only the basic composition. CHANGE every texture, color, and line to match the requested style perfectly.
    ${instruction ? `Context: ${instruction}` : ''}
    The output MUST look completely different from the original in terms of artistic execution.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: b64, mimeType: file.type } },
          { text: stylePrompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("No se pudo aplicar el estilo.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }
}

