import { GoogleGenAI } from "@google/genai";
import { PromptEngine, AnalysisMode } from "../types";

export class GeminiService {
  private static async getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  static async fileToBase64(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = reader.result as string;
        resolve(base64String.split(',')[1]);
      };
      reader.onerror = error => reject(error);
    });
  }

  static async enhanceImage(file: File): Promise<string> {
    const ai = await this.getAI();
    const base64 = await this.fileToBase64(file);

    const prompt = "SUPER-RESOLUTION RECONSTRUCTION: Act as a professional high-end image restorer. Take this image and reconstruct it with extreme clarity. Regenerate high-frequency details, sharpen edges perfectly, remove artifacts, and make it look like a high-resolution 4K photograph. Output ONLY the resulting image.";

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64, mimeType: file.type } },
          { text: prompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("No se pudo procesar la mejora de imagen.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  static async fuseImages(file1: File, file2: File, instruction?: string): Promise<string> {
    const ai = await this.getAI();
    const b1 = await this.fileToBase64(file1);
    const b2 = await this.fileToBase64(file2);

    const prompt = `DEEP CONCEPTUAL FUSION: 
    - IMAGE 1 is the 'Structural Anchor': Use its layout, composition, and spatial geometry as the foundation.
    - IMAGE 2 is the 'Aesthetic Source': Extract its textures, lighting, material properties, and main subjects.
    - GOAL: Create a single NEW image that merges these two seamlessly. 
    ${instruction ? `- CUSTOM DIRECTION: ${instruction}` : "- DIRECTION: Synthesize both into a high-quality, professional artwork."}
    The output must be a perfectly rendered new scene. Output ONLY the image bytes.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: b1, mimeType: file1.type } },
          { inlineData: { data: b2, mimeType: file2.type } },
          { text: prompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("El motor de Remix falló al generar la fusión. Intenta con imágenes más contrastadas.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  static async createSticker(prompt: string): Promise<string> {
    const ai = await this.getAI();

    const enhancedPrompt = `3D DIE-CUT STICKER: A high-quality, professional 3D sticker of '${prompt}'. 
    Style: Bold colors, thick white border outline, smooth glossy render, Pixar-style lighting, isolated on a clean plain neutral background. 
    Output ONLY the resulting image bytes.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: enhancedPrompt }]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("No se pudo generar el sticker.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }

  /**
   * Analizador Visual Extremo: Réplicas exactas y Prompts de Movimiento.
   */
  static async analyzeMedia(file: File, engine: PromptEngine, mode: AnalysisMode): Promise<string> {
    const ai = await this.getAI();
    const base64 = await this.fileToBase64(file);
    const isVideo = file.type.startsWith('video/');

    let instruction = "";

    if (mode === 'REPLICA') {
      instruction = `FORENSIC REPLICATION ANALYSIS: Act as a master prompt engineer. Analyze this image to create an ABSOLUTE REPLICA. 
      Break it down into:
      1. Subject: Physical characteristics, pose, clothing, and expression.
      2. Environment: Detailed background, depth of field, and spatial layout.
      3. Technical: Camera lens (mm), aperture (f-stop), lighting setup (e.g., Rembrandt lighting, volumetric fog), and film stock or render engine.
      4. Color: Dominant palette and mood.
      Optimize the final prompt for the ${engine} engine using its specific syntax. Provide ONLY the final prompt text.`;
    } else {
      instruction = `KINETIC MOTION ANALYSIS: Analyze the movement in this ${isVideo ? 'video' : 'image'} to create a MOTION PROMPT. 
      If it's a video, describe:
      1. Camera Motion: Pan, Tilt, Zoom, Dolly, or handheld jitter.
      2. Subject Action: Fluidity, speed, and specific physical movements.
      3. Environmental Dynamics: Wind, particles, light flickering, or physics.
      If it's an image, infer the most cinematic potential movement.
      Final goal: A prompt that describes HOW TO ANIMATE this scene. Provide ONLY the motion prompt text.`;
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Usamos Pro para máxima capacidad de análisis descriptivo
      contents: {
        parts: [
          { inlineData: { data: base64, mimeType: file.type } },
          { text: instruction }
        ]
      }
    });

    return response.text || "No se pudo generar el análisis.";
  }

  static async changeStyle(file: File, styleName: string): Promise<string> {
    const ai = await this.getAI();
    const base64 = await this.fileToBase64(file);

    const prompt = `ARTISTIC STYLE TRANSFORMATION: Take the structure of this image and RE-IMAGINE it entirely in the ${styleName} aesthetic. Change colors, lighting, and textures completely to fit ${styleName}. Professional quality only. Output ONLY image bytes.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64, mimeType: file.type } },
          { text: prompt }
        ]
      }
    });

    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part?.inlineData) throw new Error("Error al aplicar el estilo.");
    return `data:image/png;base64,${part.inlineData.data}`;
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { ToolType, AppState, GenerationResult, PromptEngine, AnalysisMode } from './types';
import { Icons, STYLES, ENGINES } from './constants';
import { GeminiService } from './services/geminiService';

const NavItem: React.FC<{ 
  id: ToolType; 
  label: string; 
  icon: React.ReactNode; 
  active: boolean; 
  onClick: (id: ToolType) => void;
  isMobile?: boolean;
}> = ({ id, label, icon, active, onClick, isMobile }) => {
  if (isMobile) {
    return (
      <button
        onClick={() => onClick(id)}
        className={`flex flex-col items-center justify-center flex-1 py-2 transition-all ${
          active ? 'text-indigo-400' : 'text-slate-500'
        }`}
      >
        <span className={`${active ? 'scale-110' : ''} transition-transform`}>{icon}</span>
        <span className="text-[10px] font-bold mt-1 uppercase tracking-tighter">{label.split(' ')[0]}</span>
      </button>
    );
  }

  return (
    <button
      onClick={() => onClick(id)}
      className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl transition-all duration-300 group ${
        active 
          ? 'bg-gradient-to-r from-indigo-600 to-pink-600 text-white shadow-lg' 
          : 'text-slate-400 hover:bg-white/5 hover:text-white'
      }`}
    >
      <span className={`${active ? 'scale-110' : 'group-hover:scale-110'} transition-transform`}>
        {icon}
      </span>
      <span className="font-semibold text-xs tracking-wide">{label}</span>
    </button>
  );
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    activeTool: ToolType.FUSION,
    isProcessing: false,
    result: null,
    error: null
  });

  const [files, setFiles] = useState<File[]>([]);
  const [prompt, setPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState(STYLES[0].name);
  const [selectedEngine, setSelectedEngine] = useState<PromptEngine>(ENGINES[0].id);
  const [analysisMode, setAnalysisMode] = useState<AnalysisMode>('REPLICA');
  const [isMobile, setIsMobile] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 1024);
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleToolChange = (tool: ToolType) => {
    setState(prev => ({ ...prev, activeTool: tool, result: null, error: null }));
    setFiles([]);
    setPrompt('');
    setCopySuccess(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, index?: number) => {
    const newFiles = Array.from(e.target.files || []);
    if (state.activeTool === ToolType.FUSION) {
      const updatedFiles = [...files];
      if (typeof index === 'number') {
        updatedFiles[index] = newFiles[0];
      } else {
        updatedFiles.push(...newFiles);
      }
      setFiles(updatedFiles.slice(0, 2));
    } else {
      setFiles(newFiles.slice(0, 1));
    }
  };

  const copyToClipboard = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    } catch (err) {
      console.error('Fallo al copiar: ', err);
    }
  };

  const processAction = async () => {
    if (state.isProcessing) return;
    setState(prev => ({ ...prev, isProcessing: true, error: null, result: null }));
    setCopySuccess(false);
    try {
      let url = '';
      let textResult = '';

      switch (state.activeTool) {
        case ToolType.ENHANCE:
          if (!files[0]) throw new Error("Selecciona una imagen.");
          url = await GeminiService.enhanceImage(files[0]);
          break;
        case ToolType.FUSION:
          if (files.length < 2 || !files[0] || !files[1]) throw new Error("Sube 2 imágenes para el Remix.");
          url = await GeminiService.fuseImages(files[0], files[1], prompt);
          break;
        case ToolType.STICKER:
          if (!prompt) throw new Error("Escribe una idea.");
          url = await GeminiService.createSticker(prompt);
          break;
        case ToolType.PROMPT_GEN:
          if (!files[0]) throw new Error("Sube un archivo para analizar.");
          textResult = await GeminiService.analyzeMedia(files[0], selectedEngine, analysisMode);
          break;
        case ToolType.STYLE:
          if (!files[0]) throw new Error("Sube una imagen.");
          url = await GeminiService.changeStyle(files[0], selectedStyle);
          break;
      }

      setState(prev => ({ 
        ...prev, 
        isProcessing: false, 
        result: { url, prompt: textResult, type: 'image' } 
      }));
    } catch (err: any) {
      setState(prev => ({ ...prev, isProcessing: false, error: err.message || 'Error inesperado' }));
    }
  };

  const canProcess = state.activeTool === ToolType.STICKER 
    ? !!prompt 
    : (state.activeTool === ToolType.FUSION ? files.length === 2 : files.length > 0);

  const navigationItems = [
    { id: ToolType.FUSION, label: "Remix Studio", icon: <Icons.Fusion /> },
    { id: ToolType.ENHANCE, label: "Mejora HD", icon: <Icons.Enhance /> },
    { id: ToolType.STYLE, label: "Estilos", icon: <Icons.Style /> },
    { id: ToolType.STICKER, label: "Stickers", icon: <Icons.Sticker /> },
    { id: ToolType.PROMPT_GEN, label: "Analizar", icon: <Icons.Analyze /> }
  ];

  return (
    <div className="flex flex-col lg:flex-row h-screen relative z-10 overflow-hidden bg-vivid text-slate-200">
      {/* Sidebar */}
      {!isMobile && (
        <aside className="w-72 glass flex flex-col p-6 gap-6 border-r border-white/5">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg">
              <Icons.Fusion />
            </div>
            <h1 className="text-lg font-black tracking-tighter text-white uppercase">Nano<span className="text-indigo-400">Vivid</span></h1>
          </div>

          <nav className="flex flex-col gap-1.5">
            {navigationItems.map(item => (
              <NavItem 
                key={item.id}
                id={item.id} 
                label={item.label} 
                icon={item.icon} 
                active={state.activeTool === item.id} 
                onClick={handleToolChange} 
              />
            ))}
          </nav>

          <div className="mt-auto p-4 bg-white/5 rounded-2xl border border-white/10 text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Motor Gratuito Activo</p>
            <p className="text-[8px] text-slate-600 mt-1">Gemini Pro Vision Enabled</p>
          </div>
        </aside>
      )}

      {/* Main Content */}
      <main className={`flex-1 overflow-y-auto no-scrollbar pt-safe ${isMobile ? 'pb-24' : 'p-12'}`}>
        <div className={`max-w-6xl mx-auto ${isMobile ? 'p-6' : ''}`}>
          <header className="mb-8 flex flex-col md:flex-row justify-between items-start gap-4">
            <div>
              <h2 className="text-3xl font-black text-white tracking-tight">
                {state.activeTool === ToolType.FUSION && "Remix & Fusión Pro"}
                {state.activeTool === ToolType.ENHANCE && "Mejora de Imagen HD"}
                {state.activeTool === ToolType.STYLE && "Estilos Artísticos"}
                {state.activeTool === ToolType.STICKER && "Sticker Lab"}
                {state.activeTool === ToolType.PROMPT_GEN && (analysisMode === 'REPLICA' ? "Réplica de Imagen Exacta" : "Ingeniería de Movimiento")}
              </h2>
              <p className="text-slate-500 text-xs mt-1 uppercase tracking-widest font-bold">Inteligencia Visual Avanzada</p>
            </div>

            <button 
              onClick={processAction}
              disabled={state.isProcessing || !canProcess}
              className="w-full md:w-auto px-10 py-4 bg-indigo-600 active:scale-95 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl disabled:opacity-20 transition-all"
            >
              {state.isProcessing ? "Escaneando..." : "Ejecutar Motor"}
            </button>
          </header>

          <div className="grid grid-cols-1 xl:grid-cols-12 gap-8">
            <div className="xl:col-span-4 space-y-6">
              {/* Media Upload Section */}
              <div className="glass p-6 rounded-3xl border-white/5">
                <div className="flex justify-between items-center mb-6">
                   <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest block">Insumo Visual</label>
                   {state.activeTool === ToolType.PROMPT_GEN && (
                     <div className="flex gap-1 bg-white/5 p-1 rounded-lg">
                        <button 
                          onClick={() => { setAnalysisMode('REPLICA'); setFiles([]); }}
                          className={`px-3 py-1 text-[9px] font-bold uppercase rounded-md transition-all ${analysisMode === 'REPLICA' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
                        >
                          Imagen
                        </button>
                        <button 
                          onClick={() => { setAnalysisMode('MOTION'); setFiles([]); }}
                          className={`px-3 py-1 text-[9px] font-bold uppercase rounded-md transition-all ${analysisMode === 'MOTION' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
                        >
                          Video
                        </button>
                     </div>
                   )}
                </div>

                <div className="w-full aspect-square relative">
                  <input 
                    type="file" 
                    onChange={handleFileChange} 
                    className="hidden" 
                    id="f-up-single" 
                    accept={analysisMode === 'MOTION' ? "video/*,image/*" : "image/*"} 
                  />
                  <label htmlFor="f-up-single" className={`w-full h-full flex flex-col items-center justify-center border-2 border-dashed rounded-2xl cursor-pointer transition-all overflow-hidden ${files[0] ? 'border-transparent' : 'border-white/10 hover:bg-white/5'}`}>
                    {files[0] ? (
                      files[0].type.startsWith('video/') ? (
                        <video 
                          src={URL.createObjectURL(files[0])} 
                          className="w-full h-full object-cover" 
                          autoPlay 
                          loop 
                          muted 
                        />
                      ) : (
                        <img src={URL.createObjectURL(files[0])} className="w-full h-full object-cover" />
                      )
                    ) : (
                      <div className="text-center p-4">
                        <p className="text-[10px] font-black text-slate-400 uppercase">Sube tu {analysisMode === 'MOTION' ? 'Video/Imagen' : 'Imagen'}</p>
                        <p className="text-[8px] text-slate-600 mt-2 uppercase tracking-tighter">Formatos: {analysisMode === 'MOTION' ? 'MP4, WebM, MOV, JPG' : 'JPG, PNG, WEBP'}</p>
                      </div>
                    )}
                  </label>
                </div>
              </div>

              {/* Engine Selection for Analysis */}
              {state.activeTool === ToolType.PROMPT_GEN && (
                <div className="glass p-6 rounded-3xl border-white/5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block">Motor de Optimización</label>
                  <div className="grid grid-cols-1 gap-2">
                    {ENGINES.map(engine => (
                      <button
                        key={engine.id}
                        onClick={() => setSelectedEngine(engine.id)}
                        className={`p-3 rounded-xl border text-left flex items-center gap-3 transition-all ${selectedEngine === engine.id ? 'border-indigo-500 bg-indigo-500/10 shadow-lg' : 'border-white/5 hover:bg-white/5'}`}
                      >
                        <span className="text-xl">{engine.icon}</span>
                        <div>
                          <p className="text-[11px] font-bold text-white uppercase">{engine.name}</p>
                          <p className="text-[9px] text-slate-500 leading-none mt-1">{engine.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Styles and Options for other tools */}
              {state.activeTool === ToolType.STYLE && (
                <div className="glass p-6 rounded-3xl border-white/5 max-h-[400px] overflow-y-auto no-scrollbar">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block">Catálogo de Estilos</label>
                  <div className="space-y-2">
                    {STYLES.map(s => (
                      <button 
                        key={s.id} 
                        onClick={() => setSelectedStyle(s.name)} 
                        className={`w-full p-4 rounded-2xl border text-left transition-all flex items-center gap-4 ${selectedStyle === s.name ? 'border-indigo-500 bg-indigo-500/10 shadow-[0_0_15px_rgba(99,102,241,0.1)]' : 'border-white/5 hover:bg-white/5'}`}
                      >
                        <div className={`w-3 h-3 rounded-full flex-shrink-0 ${s.previewColor}`} />
                        <div>
                          <p className="text-[11px] font-bold text-white uppercase">{s.name}</p>
                          <p className="text-[9px] text-slate-500 mt-0.5">{s.description}</p>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="xl:col-span-8">
              <div className="glass p-6 rounded-[2.5rem] border-white/5 min-h-[400px] lg:min-h-[650px] flex flex-col relative overflow-hidden shadow-2xl">
                {state.isProcessing && (
                  <div className="absolute inset-0 z-30 bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center p-12 text-center">
                    <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6 shadow-[0_0_20px_rgba(99,102,241,0.3)]"></div>
                    <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">Escaneo Forense</h3>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.2em]">Analizando capas de {analysisMode === 'MOTION' ? 'movimiento' : 'datos visuales'}...</p>
                  </div>
                )}

                <div className="flex-1 flex flex-col items-center justify-center bg-black/40 rounded-3xl border border-white/5 overflow-hidden shadow-inner">
                  {state.result ? (
                    state.result.url && state.activeTool !== ToolType.PROMPT_GEN ? (
                      <img src={state.result.url} className="max-w-full max-h-[75vh] object-contain animate-in fade-in zoom-in duration-700" alt="Resultado" />
                    ) : (
                      <div className="p-8 w-full h-full flex flex-col relative">
                        <div className="flex justify-between items-center mb-6">
                           <div className="flex items-center gap-3">
                             <span className="text-2xl">{analysisMode === 'MOTION' ? '🎬' : ENGINES.find(e => e.id === selectedEngine)?.icon}</span>
                             <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.2em]">
                               {analysisMode === 'MOTION' ? 'Prompt de Movimiento Generado' : `Replica Exacta para ${ENGINES.find(e => e.id === selectedEngine)?.name}`}
                             </span>
                           </div>
                           <button 
                            onClick={() => copyToClipboard(state.result?.prompt || '')}
                            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all shadow-lg ${copySuccess ? 'bg-green-600 text-white scale-105' : 'bg-indigo-600 hover:bg-indigo-500 text-white'}`}
                           >
                             <Icons.Copy /> {copySuccess ? '¡Copiado!' : 'Copiar al Portapapeles'}
                           </button>
                        </div>
                        <div className="flex-1 overflow-y-auto no-scrollbar bg-black/50 p-8 rounded-[2rem] border border-white/5 shadow-2xl">
                           <pre className="text-slate-300 text-sm leading-relaxed whitespace-pre-wrap font-mono italic">
                             {state.result.prompt}
                           </pre>
                        </div>
                      </div>
                    )
                  ) : (
                    <div className="text-center opacity-10 py-32 pointer-events-none flex flex-col items-center">
                      <div className="scale-[3] mb-10 text-slate-400"><Icons.Analyze /></div>
                      <p className="font-black tracking-[0.6em] text-white uppercase text-[12px]">Monitor de Análisis</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Mobile Nav */}
      {isMobile && (
        <nav className="fixed bottom-0 left-0 right-0 glass border-t border-white/10 flex justify-around px-2 pb-safe z-50">
          {navigationItems.map(item => (
            <NavItem 
              key={item.id}
              id={item.id} 
              label={item.label} 
              icon={item.icon} 
              active={state.activeTool === item.id} 
              onClick={handleToolChange}
              isMobile
            />
          ))}
        </nav>
      )}
    </div>
  );
};

